async (params, browser) => {
  // Open article page
  await browser.open(`${params.article_url}`)

  // Wait for article to load
  await browser.waitForSelector('article, h1, [data-testid=\'storyTitle\']', 15000)

  // Let page fully render
  await browser.wait(2000)

  // Scroll to load content
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Scroll further down
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract article details
  const article_data = await browser.evaluate(`const titleEl = document.querySelector('h1, [data-testid="storyTitle"]'); const authorEl = document.querySelector('a[data-testid="authorName"], a[rel="author"], [class*="author"] a'); const pubEl = document.querySelector('[data-testid="publicationName"] a, [class*="publication"] a'); const dateEl = document.querySelector('time, [data-testid="storyPublishDate"], span[class*="date"]'); const readTimeEl = document.querySelector('[class*="readingTime"], span[class*="read-time"]'); const clapsEl = document.querySelector('button[data-testid="clap"] span, [class*="clap"] span, [class*="clapCount"]'); const responsesEl = document.querySelector('button[data-testid="responses"] span, a[href*="responses"] span, [class*="responseCount"]'); const contentEls = document.querySelectorAll('article p, article [class*="paragraph"], section p'); let content = ''; for (let i = 0; i < contentEls.length; i++) { content += contentEls[i].textContent.trim() + '\n'; if (content.length > 2000) break; } const tagEls = document.querySelectorAll('a[href*="/tag/"], [class*="tags"] a'); const tags = []; tagEls.forEach(function(el) { const t = el.textContent.trim(); if (t && t.length < 50 && !tags.includes(t)) tags.push(t); }); const imgEl = document.querySelector('article img[src*="miro.medium"], article figure img'); const subtitleEl = document.querySelector('h2[class*="subtitle"], article h2:first-of-type'); return { title: titleEl ? titleEl.textContent.trim() : '', subtitle: subtitleEl ? subtitleEl.textContent.trim() : '', author: authorEl ? authorEl.textContent.trim() : '', publication: pubEl ? pubEl.textContent.trim() : '', date: dateEl ? (dateEl.getAttribute('datetime') || dateEl.textContent.trim()) : '', read_time: readTimeEl ? readTimeEl.textContent.trim() : '', claps: clapsEl ? clapsEl.textContent.trim() : '', responses: responsesEl ? responsesEl.textContent.trim() : '', content_preview: content.substring(0, 2000), tags: tags.slice(0, 10), image: imgEl ? imgEl.getAttribute('src') : '', url: window.location.href }`)

  return article_data
}
